		{ID: uuid.New().String(), RunID: runID.String(), Sequence: 1, Type: "plan", State: "succeeded"},
		{ID: uuid.New().String(), RunID: runID.String(), Sequence: 2, Type: "implement", State: "running"},
	}

	r := newResolver(srv, nil)
