		t.Errorf("MaxFilesChanged = %d, want 30", out.ScopePrecheck.MaxFilesChanged)
	}
	if out.ScopePrecheck.ScannedFiles != 29 {
		t.Errorf("ScannedFiles = %d, want 29", out.ScopePrecheck.ScannedFiles)
	}
}

